pub async fn add_user_task(filename: &str, args: Vec<&str>, envp: Vec<&str>) -> TaskId {
    let curr_task = current_task().expect("no current task");
    let task = UserTask::new(Weak::new(), USER_WORK_DIR);
    task.before_run();

    // 设置 stdin/stdout/stderr (fd 0, 1, 2) 连接到 TTY
    {
        let mut pcb = task.pcb.lock();
        // 确保 fd_table 至少能容纳 fd 0/1/2
        while pcb.fd_table.len() <= 2 {
            pcb.fd_table.push(None);
        }
        if pcb.fd_table[0].is_none() {
            pcb.fd_table[0] = File::open("/dev/stdin", OpenFlags::RDONLY).ok().map(Arc::new);
        }
        if pcb.fd_table[1].is_none() {
            pcb.fd_table[1] = File::open("/dev/stdout", OpenFlags::WRONLY).ok().map(Arc::new);
        }
        if pcb.fd_table[2].is_none() {
            pcb.fd_table[2] = File::open("/dev/stderr", OpenFlags::WRONLY).ok().map(Arc::new);
        }
    }

    exec_with_process(
        task.clone(),
        PathBuf::empty(),
        String::from(filename),
        args.into_iter().map(String::from).collect(),
        envp.into_iter().map(String::from).collect(),
    )
    .expect("can't add task to excutor");
    curr_task.before_run();
    thread::spawn(task.clone(), user_entry());

    // 第一个用户进程即为 init (pid 1)，用于孤儿进程重托管
    set_init_task(task.clone());

    task.get_task_id()
}

#[inline]
pub fn current_user_task() -> Arc<UserTask> {
    current_task().and_then(|t| t.downcast_arc::<UserTask>().ok()).unwrap()
}

use core::sync::atomic::{AtomicBool, Ordering};
static INIT_TASK_SET: AtomicBool = AtomicBool::new(false);
static mut INIT_TASK_PTR: Option<Arc<UserTask>> = None;

pub fn set_init_task(task: Arc<UserTask>) {
    if !INIT_TASK_SET.swap(true, Ordering::SeqCst) {
        unsafe {
            INIT_TASK_PTR = Some(task);
        }
    }
}

pub fn get_init_task() -> Option<Arc<UserTask>> {
    if INIT_TASK_SET.load(Ordering::SeqCst) {
        unsafe { INIT_TASK_PTR.clone() }
    } else {
        None
    }
}

