use super::SysResult;
use crate::syscall::types::mm::map_mprot_to_flags;
use crate::tasks::{MemArea, MemType};
use crate::user::UserTaskContainer;
use crate::utils::useref::UserRef;
use devices::PAGE_SIZE;
use libc_types::mman::{MSyncFlags, MapFlags, MmapProt};
use log::debug;
use polyhal::{MappingSize, VirtAddr};
use runtime::frame::{aligndown, alignup};
use syscalls::Errno;

// The high 25bits in sv39 should be the same as bit 38.
const MAP_AREA_START: usize = 0x2_0000_0000;

impl UserTaskContainer {
    pub fn sys_brk(&self, addr: usize) -> SysResult {
        let heap = self.task.pcb.lock().heap;
        debug!("sys_brk @ new: {:#x} old: {:#x}", addr, heap);
        match addr {
            0 => Ok(heap),
            _ => Ok(self.task.sbrk(addr)),
        }
    }

    pub fn sys_mmap(
        &self,
        start: usize,
        mut len: usize,
        prot: usize,
        flags: usize,
        fd: usize,
        off: usize,
    ) -> SysResult {
        let flags = MapFlags::from_bits_truncate(flags as _);
        let prot = MmapProt::from_bits_truncate(prot as _);
        len = alignup(len, PAGE_SIZE);
        debug!(
            "[task {}] sys_mmap @ start: {:#x}, len: {:#x}, prot: {:?}, flags: {:?}, fd: {}, offset: {}",
            self.tid, start, len, prot, flags, fd as isize, off
        );
        let file = self.task.get_fd(fd);

        let addr = self.task.get_last_free_addr();

        let addr = if start == 0 {
            if usize::from(addr) >= MAP_AREA_START {
                addr
            } else {
                VirtAddr::from(MAP_AREA_START)
            }
        } else {
            VirtAddr::new(start)
        };

        if len == 0 {
            return Ok(addr.into());
        }

        if flags.contains(MapFlags::FIXED) {
            let overlaped = self
                .task
                .pcb
                .lock()
                .memset
                .overlapping(addr.raw(), addr.raw() + len);
            if overlaped {
                self.task.pcb.lock().memset.sub_area(
                    addr.raw(),
                    addr.raw() + len,
                    &self.task.page_table,
                );
            }
        } else if self
            .task
            .pcb
            .lock()
            .memset
            .overlapping(addr.raw(), addr.raw() + len)
        {
            return Err(Errno::EINVAL);
        }

        if flags.contains(MapFlags::SHARED) {
            match &file {
                Some(file) => self
                    .task
                    .map_frames(
                        addr,
                        MemType::ShareFile,
                        (len + PAGE_SIZE - 1) / PAGE_SIZE,
                        Some(file.get_bare_file()),
                        off,
                        usize::from(addr),
                        len,
                    )
                    .ok_or(Errno::EFAULT)?,
                None => {
                    let paddr = self
                        .task
                        .frame_alloc(addr, MemType::Shared, len.div_ceil(PAGE_SIZE))
                        .ok_or(Errno::EFAULT)?;

                    for i in 0..(len + PAGE_SIZE - 1) / PAGE_SIZE {
                        self.task.map(
                            paddr + i * PAGE_SIZE,
                            addr + i * PAGE_SIZE,
                            map_mprot_to_flags(prot),
                        );
                    }
                    paddr
                }
            };
        } else if file.is_some() {
            self.task
                .frame_alloc(addr, MemType::Mmap, len.div_ceil(PAGE_SIZE))
                .ok_or(Errno::EFAULT)?;
        } else {
            self.task.pcb.lock().memset.push(MemArea {
                mtype: MemType::Mmap,
                mtrackers: vec![],
                file: None,
                offset: 0,
                start: addr.raw(),
                len,
            });
        };

        if let Some(file) = file {
            let buffer = UserRef::<u8>::from(addr).slice_mut_with_len(len);
            file.readat(off, buffer)?;
        }
        Ok(addr.into())
    }

    pub fn sys_munmap(&self, start: usize, len: usize) -> SysResult {
        debug!("sys_munmap @ start: {:#x}, len: {:#x}", start, len);
        self.task.inner_map(|pcb| {
            pcb.memset
                .sub_area(start, start + len, &self.task.page_table);
        });
        Ok(0)
    }

    pub fn sys_mprotect(&self, start: usize, len: usize, prot: u32) -> SysResult {
        let prot = MmapProt::from_bits(prot).ok_or(Errno::EINVAL)?;
        let start = aligndown(start, PAGE_SIZE);
        let end = alignup(start + len, PAGE_SIZE);
        let mmap_flags = map_mprot_to_flags(prot);
        debug!(
            "sys_mprotect @ start: {:#x}, len: {:#x}, prot: {:?}, flags: {:?}",
            start, len, prot, mmap_flags
        );

        // 遍历页表，修改权限：unmap 旧映射，用新权限 remap
        for addr in (start..end).step_by(PAGE_SIZE) {
            let va = VirtAddr::from(addr);
            if let Some((paddr, _flags)) = self.task.page_table.translate(va) {
                let _ = self.task.page_table.unmap_page(va);
                self.task.page_table.map_page(va, paddr, mmap_flags, MappingSize::Page4KB);
            }
        }
        Ok(0)
    }

    pub fn sys_msync(&self, addr: usize, len: usize, flags: u32) -> SysResult {
        let flags = MSyncFlags::from_bits_truncate(flags);
        debug!(
            "sys_msync @ addr: {:#x} len: {:#x} flags: {:?}",
            addr, len, flags
        );
        // use it temporarily
        Ok(0)
    }
}

use super::SysResult;
use crate::{tasks::WaitSignal, user::UserTaskContainer, utils::useref::UserRef};
use executor::yield_now;
use libc_types::{
    internal::SigAction,
    signal::SignalNum,
    types::{SigMaskHow, SigSet},
};
use log::debug;
use syscalls::Errno;

/*
 * 忽略信号：不采取任何操作、有两个信号不能被忽略：SIGKILL和SIGSTOP。
 * 注：SIGKILL和SIGSTOP这两个信号是不会被捕捉、阻塞、忽略的。
 * 捕获并处理信号：内核中断正在执行的代码，转去执行信号的处理函数。
 * 执行默认操作：默认操作通常是终止进程，这取决于被发送的信号。
 *
 *
 *  //struct sigaction 类型用来描述对信号的处理，定义如下：
 *
 *  struct sigaction
 *  {
 *      void     (*sa_handler)(int);
 *      void     (*sa_sigaction)(int, siginfo_t *, void *);
 *      sigset_t  sa_mask;
 *      int       sa_flags;
 *      void     (*sa_restorer)(void);
 *  };
 *  在这个结构体中，
 *  成员 sa_handler 是一个函数指针，包含一个信号处理函数的地址，与signal函数类似
 *  成员sa_sigaction 则是另一个信号处理函数，它有三个参数，可以获得关于信号的更详细的信息。
 *  int iSignNum : 传入的信号
 *  //siginfo_t *pSignInfo : 该信号相关的一些信息,他是一个结构体原型如下
 *  siginfo_t {
 *      int      si_signo;    /* 信号值，对所有信号有意义 */
 *      int      si_errno;    /* errno 值，对所有信号有意义 */
 *      int      si_code;     /* 信号产生的原因，对所有信号有意义 */
 *      int      si_trapno;   /* Trap number that caused
 *                               hardware-generated signal
 *                               (unused on most architectures) */
 *      pid_t    si_pid;      /* 发送信号的进程ID */
 *      uid_t    si_uid;      /* 发送信号进程的真实用户ID */
 *      int      si_status;   /* 对出状态，对SIGCHLD 有意义 */
 *      clock_t  si_utime;    /* 用户消耗的时间，对SIGCHLD有意义 */
 *      clock_t  si_stime;    /* 内核消耗的时间，对SIGCHLD有意义 */
 *      sigval_t si_value;    /* 信号值，对所有实时有意义，是一个联合数据结构，可以为一个整数（由si_int标示，也可以为一个指针，由si_ptr标示） */
 *      int      si_int;      /* POSIX.1b signal */
 *      void    *si_ptr;      /* POSIX.1b signal */
 *      int      si_overrun;  /* Timer overrun count; POSIX.1b timers */
 *      int      si_timerid;  /* Timer ID; POSIX.1b timers */
 *      void    *si_addr;     /* 触发fault的内存地址，对SIGILL,SIGFPE,SIGSEGV,SIGBUS 信号有意义 */
 *      long     si_band;     /* 对SIGPOLL信号有意义 */
 *      int      si_fd;       /* 对SIGPOLL信号有意义 */
 *      short    si_addr_lsb; /* Least significant bit of address
 *                               (since kernel 2.6.32) */
 *  }
 */

impl UserTaskContainer {
    /// TODO: finish sigtimedwait
    pub async fn sys_sigtimedwait(&self) -> SysResult {
        debug!("sys_sigtimedwait @ ");
        WaitSignal(self.task.clone()).await;
        // let task = current_user_task();
        // task.inner_map(|x| x.signal.has_signal());
        // Err(LinuxError::EAGAIN)
        Ok(0)
    }

    pub fn sys_sigprocmask(
        &self,
        how: u8,
        set: UserRef<SigSet>,
        oldset: UserRef<SigSet>,
    ) -> SysResult {
        debug!(
            "[task {}] sys_sigprocmask @ how: {:#x}, set: {}, oldset: {}",
            self.tid, how, set, oldset
        );
        let how = SigMaskHow::try_from(how).map_err(|_| Errno::EINVAL)?;
        let mut tcb = self.task.tcb.write();
        if oldset.is_valid() {
            oldset.write(tcb.sigmask);
        }
        if set.is_valid() {
            tcb.sigmask.handle(how, &set.read())
        }
        drop(tcb);
        // Err(LinuxError::EPERM)
        Ok(0)
    }

    /// 其次，每个线程都有自己独立的signal mask，但所有线程共享进程的signal action。这意味着，
    /// 你可以在线程中调用pthread_sigmask(不是sigmask)来决定本线程阻塞哪些信号。
    /// 但你不能调用sigaction来指定单个线程的信号处理方式。如果在某个线程中调用了sigaction处理某个信号，
    /// 那么这个进程中的未阻塞这个信号的线程在收到这个信号都会按同一种方式处理这个信号。
    /// 另外，注意子线程的mask是会从主线程继承而来的。

    pub fn sys_sigaction(
        &self,
        sig: usize,
        act: UserRef<SigAction>,
        oldact: UserRef<SigAction>,
    ) -> SysResult {
        let signal = SignalNum::from_num(sig);
        debug!(
            "sys_sigaction @ sig: {:?}, act: {}, oldact: {}",
            signal, act, oldact
        );
        if oldact.is_valid() {
            oldact.write(self.task.pcb.lock().sigaction[sig].clone());
        }
        if act.is_valid() {
            self.task.pcb.lock().sigaction[sig] = act.read();
        }
        Ok(0)
    }
    pub async fn sys_sigsuspend(&self, sigset: UserRef<SignalNum>) -> SysResult {
        let signal = sigset.read();
        debug!("sys_sigsuspend @ sigset: {:?} signal: {:?}", sigset, signal);
        loop {
            self.check_timer();
            let tcb = self.task.tcb.read();
            if !tcb.signal.is_empty(None) {
                break;
            }
            drop(tcb);
            yield_now().await;
        }
        debug!("sys_sigsuspend @ sigset: {:?}", signal);
        Ok(0)
    }

    #[cfg(target_arch = "x86_64")]
    pub async fn sys_pause(&self) -> SysResult {
        debug!("sys_pause @ ");
        loop {
            self.check_timer();
            let tcb = self.task.tcb.read();
            if !tcb.signal.is_empty(None) {
                break;
            }
            drop(tcb);
            yield_now().await;
        }
        Ok(0)
    }
}

