/// 将 `MapTrack.rwx` (u8) 转换为 `MappingFlags`
fn rwx_to_flags(rwx: u8) -> MappingFlags {
    let mut flags = MappingFlags::U;  // 用户态可访问
    if rwx & 0b100 != 0 { flags |= MappingFlags::R; }
    if rwx & 0b010 != 0 { flags |= MappingFlags::W; }
    if rwx & 0b001 != 0 { flags |= MappingFlags::X; }
    flags
}

