impl Clone for File {
    fn clone(&self) -> Self {
        Self {
            inner: self.inner.clone(),
            path_buf: self.path_buf.clone(),
            offset: Mutex::new(self.offset.lock().clone()),
            flags: Mutex::new(self.flags.lock().clone()),
            close_on_exec: self.close_on_exec,
        }
    }
