        if ty == FileType::Directory {
            let new_inner = Arc::new(RamDirInner {
                name: String::from(name),
                children: Mutex::new(Vec::new()),
            });
            self.inner
                .children
                .lock()
                .push(FileContainer::Dir(new_inner.clone()));
