pub fn init_driver(node: &Node) -> Arc<dyn Driver> {
    let addr = node.find_property("reg").unwrap().raw_value()[4..8]
        .iter()
        .fold(0, |acc, x: &u8| (acc << 8) | (*x as usize));
    let plic = Arc::new(PLIC {
        base: VIRT_ADDR_START + addr,
    });
    plic.set_thresold(0, true, 0);
    // enable_external_irq();
    plic
}

