    // register the drivers in the IRQ MANAGER.
    if let Some(plic) = INT_DEVICE.try_get() {
        for (irq, driver) in IRQ_MANAGER.lock().iter() {
            plic.register_irq(*irq, driver.clone());
        }
    }
}

