/// Memory set for storing the memory and its map relation.
#[derive(Debug)]
pub struct MemSet(Vec<MemArea>);

/// Deref for memset, let it iterable
impl Deref for MemSet {
    type Target = Vec<MemArea>;

    fn deref(&self) -> &Self::Target {
        &self.0
    }
}

/// DerefMut for memset, let it iterable
impl DerefMut for MemSet {
    fn deref_mut(&mut self) -> &mut Self::Target {
        &mut self.0
    }
}

impl<'a> MemSet {
    pub fn new(vec: Vec<MemArea>) -> Self {
        Self(vec)
    }

    pub fn overlapping(&self, start: usize, end: usize) -> bool {
        self.0.iter().find(|x| x.overlapping(start, end)).is_some()
    }

    pub fn sub_area(&mut self, start: usize, end: usize, pt: &PageTable) {
        let mut new_set = Vec::new();
        self.0.retain_mut(|area| {
            let res = area.sub(start, end, pt);
            if let Some(new_area) = res {
                new_set.push(new_area);
            }
            area.len != 0
        });
        self.0.extend(new_set);
    }

    pub fn clear(&mut self) {
        self.0.clear();
    }
}

#[derive(Clone, PartialEq, Debug, Copy)]
pub enum MemType {
    CodeSection,
    Stack,
    Mmap,
    Shared,
    ShareFile,
}

#[derive(Clone)]
pub struct MapTrack {
    pub vaddr: VirtAddr,
    pub tracker: Arc<FrameTracker>,
    pub rwx: u8,
}

impl Debug for MapTrack {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        f.write_fmt(format_args!(
            "{:#x} -> {:#x}",
            self.vaddr.raw(),
            self.tracker.0.raw()
        ))
    }
}

#[derive(Clone)]
pub struct MemArea {
    pub mtype: MemType,
    pub mtrackers: Vec<MapTrack>,
    pub file: Option<Arc<dyn INodeInterface>>,
    pub offset: usize,
    pub start: usize,
    pub len: usize,
}

impl Debug for MemArea {
    fn fmt(&self, f: &mut core::fmt::Formatter<'_>) -> core::fmt::Result {
        f.debug_struct("MemArea")
            .field("mtype", &self.mtype)
            .field("mtrackers", &self.mtrackers)
            .field("start", &self.start)
            .field("len", &self.len)
            .finish()
    }
}

impl MemArea {
    /// Check the memory is overlapping.
    pub fn overlapping(&self, start: usize, end: usize) -> bool {
        let self_end = self.start + self.len;
        let res =
            !((start <= self.start && end <= self.start) || (start >= self_end && end >= self_end));
        res
    }

    /// write page to file
    pub fn write_page(&self, mtracker: &MapTrack) {
        assert!(self.file.is_some());
        if let Some(file) = &self.file {
            let offset = mtracker.vaddr.raw() + self.offset - self.start;
            file.writeat(offset, mtracker.tracker.0.slice_mut_with_len(PAGE_SIZE))
                .expect("can't write data back to mapped file.");
        }
    }

    /// Sub the memory from this memory area.
    /// the return value indicates whether the memory is splited.
    pub fn sub(&mut self, start: usize, end: usize, pt: &PageTable) -> Option<MemArea> {
        if !self.overlapping(start, end) {
            return None;
        }
        let range = self.start..self.start + self.len;
        let jrange = start..end;

        if range.contains(&start) && range.contains(&end) {
            self.len = start - self.start;
            let new_area_range = end..range.end;

            if let Some(_file) = &self.file {
                self.mtrackers
                    .iter()
                    .filter(|x| jrange.contains(&x.vaddr.raw()))
                    .for_each(|x| {
                        self.write_page(x);
                    });
            };
            // drop the sub memory area pages.
            self.mtrackers
                .retain(|x| !new_area_range.contains(&x.vaddr.raw()));
            return Some(MemArea {
                mtype: self.mtype,
                mtrackers: self
                    .mtrackers
                    .extract_if(.., |x| new_area_range.contains(&x.vaddr.raw()))
                    .collect(),
                file: self.file.clone(),
                start: end,
                offset: end - self.start,
                len: new_area_range.len(),
            });
        }

        if jrange.contains(&self.start) && jrange.contains(&range.end) {
            self.len = 0;
            // TIPS: This area will be remove outside this function.
            // So return the None.
            if let Some(_file) = &self.file {
                self.mtrackers
                    .iter()
                    .filter(|x| jrange.contains(&x.vaddr.raw()))
                    .for_each(|x| self.write_page(x));
            };
            self.mtrackers.retain(|x| {
                pt.unmap_page(x.vaddr);
                false
            });
            return None;
        }

        if range.contains(&start) {
            // self.len = cmp::min(start - self.start, self.len);
            self.len = start - self.start;
        } else if jrange.contains(&self.start) {
            self.len = self.start + self.len - end;
            self.start = end;
        }
        if let Some(_file) = &self.file {
            self.mtrackers
                .iter()
                .filter(|x| jrange.contains(&x.vaddr.raw()))
                .for_each(|x| self.write_page(x));
        };
        // drop the sub memory area pages.
        let new_self_rang = self.start..self.start + self.len;
        self.mtrackers
            .extract_if(.., |x| !new_self_rang.contains(&x.vaddr.raw()))
            .for_each(|x| pt.unmap_page(x.vaddr));
        None
    }

    /// Check the memory area whether contains the specified address.
    pub fn contains(&self, addr: usize) -> bool {
        self.start <= addr && addr < self.start + self.len
    }
}

impl Drop for MemArea {
    fn drop(&mut self) {
        match &self.mtype {
            MemType::ShareFile => {
                let start = self.start;
                let len = self.len;
                let mapfile = self.file.clone().unwrap();
                for tracker in &self.mtrackers {
                    if Arc::strong_count(&tracker.tracker) > 1 {
                        continue;
                    }

                    let offset = tracker.vaddr.raw() - start;
                    let wlen = min(len - offset, PAGE_SIZE);

                    mapfile
                        .writeat(offset, tracker.tracker.0.slice_mut_with_len(wlen))
                        .expect("can't write data to file at drop");
                }
            }
            _ => {}
        }
    }
}

use super::SysResult;
use crate::{tasks::WaitHandleAbleSignal, user::UserTaskContainer, utils::useref::UserRef};
use core::{
    future::Future,
    ops::Add,
    pin::Pin,
    task::{Context, Poll},
    time::Duration,
};
use executor::select;
use libc_types::{
    time::ITimerVal,
    times::TMS,
    types::{TimeSpec, TimeVal},
};
use log::{debug, warn};
use polyhal::timer::{current_time, get_ticks};
use syscalls::Errno;

impl UserTaskContainer {
    pub fn sys_gettimeofday(&self, tv_ptr: UserRef<TimeVal>, timezone_ptr: usize) -> SysResult {
        debug!(
            "sys_gettimeofday @ tv_ptr: {}, timezone: {:#x}",
            tv_ptr, timezone_ptr
        );
        tv_ptr.write(current_time().into());
        Ok(0)
    }

    pub async fn sys_nanosleep(
        &self,
        req_ptr: UserRef<TimeSpec>,
        rem_ptr: UserRef<TimeSpec>,
    ) -> SysResult {
        debug!(
            "[task {}] sys_nanosleep @ req_ptr: {}, rem_ptr: {}",
            self.tid, req_ptr, rem_ptr
        );
        let req: Duration = req_ptr.read().into();
        debug!("nano sleep {} nseconds", req.as_nanos());

        let res = match select(
            WaitHandleAbleSignal(self.task.clone()),
            WaitUntilsec(current_time() + req),
        )
        .await
        {
            executor::Either::Right(_) => Ok(0),
            executor::Either::Left(_) => Err(Errno::EINTR),
        };
        if rem_ptr.is_valid() {
            rem_ptr.write(Default::default());
        }
        res
    }

    pub fn sys_times(&self, tms_ptr: UserRef<TMS>) -> SysResult {
        debug!("sys_times @ tms: {}", tms_ptr);
        self.task.inner_map(|x| tms_ptr.write(x.tms));
        Ok(get_ticks() as _)
    }

    pub fn sys_clock_gettime(&self, clock_id: usize, times_ptr: UserRef<TimeSpec>) -> SysResult {
        debug!(
            "[task {}] sys_clock_gettime @ clock_id: {}, times_ptr: {}",
            self.tid, clock_id, times_ptr
        );

        let dura = match clock_id {
            0 => current_time(), // CLOCK_REALTIME
            1 => current_time(), // CLOCK_MONOTONIC
            2 => {
                warn!("CLOCK_PROCESS_CPUTIME_ID not implemented");
                Duration::ZERO
            }
            3 => {
                warn!("CLOCK_THREAD_CPUTIME_ID not implemented");
                Duration::ZERO
            }
            _ => return Err(Errno::EINVAL),
        };
        log::debug!("dura: {:#x?}", dura);
        times_ptr.write(dura.into());
        Ok(0)
    }

    #[inline]
    pub fn sys_clock_getres(&self, clock_id: usize, times_ptr: UserRef<TimeSpec>) -> SysResult {
        debug!("clock_getres @ {} {:#x?}", clock_id, times_ptr);
        if times_ptr.is_valid() {
            times_ptr.write(Duration::from_nanos(1).into());
        }
        Ok(0)
    }
    pub fn sys_setitimer(
        &self,
        which: usize,
        times_ptr: UserRef<ITimerVal>,
        old_timer_ptr: UserRef<ITimerVal>,
    ) -> SysResult {
        debug!(
            "[task {}] sys_setitimer @ which: {} times_ptr: {} old_timer_ptr: {}",
            self.tid, which, times_ptr, old_timer_ptr
        );

        if which == 0 {
            let mut pcb = self.task.pcb.lock();
            if old_timer_ptr.is_valid() {
                old_timer_ptr.write(pcb.timer[0].timer);
            }

            if times_ptr.is_valid() {
                let current_timval: TimeVal = current_time().into();
                let new_timer = times_ptr.read();
                pcb.timer[0].timer = new_timer;
                pcb.timer[0].next = current_timval.add(pcb.timer[0].timer.value);
                if new_timer.value.sec == 0 && new_timer.value.usec == 0 {
                    pcb.timer[0].next = Default::default();
                    pcb.timer[0].last = Default::default();
                }
            }
            Ok(0)
        } else {
            Err(Errno::EPERM)
        }
    }

    pub async fn sys_clock_nanosleep(
        &self,
        clock_id: usize,
        flags: usize,
        req_ptr: UserRef<TimeSpec>,
        rem_ptr: UserRef<TimeSpec>,
    ) -> SysResult {
        debug!(
            "[task {}] sys_clock_nanosleep @ clock_id: {}, flags: {:#x} req_ptr: {}, rem_ptr: {}",
            self.tid, clock_id, flags, req_ptr, rem_ptr
        );

        let interval = req_ptr.read().into();
        if flags == 1 {
            WaitUntilsec(interval).await;
            if rem_ptr.is_valid() {
                rem_ptr.write(Default::default());
            }
        } else {
            debug!("nano sleep {} nseconds", interval.as_nanos());
            WaitUntilsec(current_time() + interval).await;
        }

        Ok(0)
    }
}

pub struct WaitUntilsec(pub Duration);

impl Future for WaitUntilsec {
    type Output = ();

    fn poll(self: Pin<&mut Self>, _cx: &mut Context<'_>) -> Poll<Self::Output> {
        let ns = current_time();

        match ns > self.0 {
            true => Poll::Ready(()),
            false => Poll::Pending,
        }
    }
}

#[allow(dead_code)]
pub fn wait_ms(ms: usize) -> WaitUntilsec {
    WaitUntilsec(current_time() + Duration::from_millis(ms as _))
}

use super::SysResult;
use crate::tasks::{MapedSharedMemory, SharedMemory, SHARED_MEMORY};
use crate::user::UserTaskContainer;
use alloc::{sync::Arc, vec::Vec};
use devices::PAGE_SIZE;
use log::debug;
use polyhal::{va, MappingFlags};
use runtime::frame::{frame_alloc_much, FrameTracker};
use syscalls::Errno;

impl UserTaskContainer {
    pub fn sys_shmget(&self, mut key: usize, size: usize, shmflg: usize) -> SysResult {
        debug!(
            "sys_shmget @ key: {}, size: {}, shmflg: {:#o}",
            key, size, shmflg
        );
        if key == 0 {
            key = SHARED_MEMORY.lock().keys().cloned().max().unwrap_or(0) + 1;
        }
        let mem = SHARED_MEMORY.lock().get(&key).cloned();
        if mem.is_some() {
            return Ok(key);
        }
        if shmflg & 01000 > 0 {
            let shm: Vec<Arc<FrameTracker>> = frame_alloc_much(size.div_ceil(PAGE_SIZE))
                .expect("can't alloc page in shm")
                .into_iter()
                .map(Arc::new)
                .collect();
            SHARED_MEMORY
                .lock()
                .insert(key, Arc::new(SharedMemory::new(shm)));
            return Ok(key);
        }
        Err(Errno::ENOENT)
    }

    pub fn sys_shmat(&self, shmid: usize, shmaddr: usize, shmflg: usize) -> SysResult {
        debug!(
            "sys_shmat @ shmid: {}, shmaddr: {}, shmflg: {:#o}",
            shmid, shmaddr, shmflg
        );
        let vaddr = self.task.get_last_free_addr();

        let vaddr = if shmaddr == 0 {
            if vaddr >= va!(0x4000_0000) {
                vaddr
            } else {
                va!(0x4000_0000)
            }
        } else {
            va!(shmaddr)
        };
        let trackers = SHARED_MEMORY.lock().get(&shmid).cloned();
        if trackers.is_none() {
            return Err(Errno::ENOENT);
        }
        trackers
            .as_ref()
            .unwrap()
            .trackers
            .iter()
            .enumerate()
            .for_each(|(i, x)| {
                debug!("map {:?} @ {:?}", vaddr.raw() + i * PAGE_SIZE, x.0);
                self.task
                    .map(x.0, vaddr + i * PAGE_SIZE, MappingFlags::URWX);
            });
        let size = trackers.as_ref().unwrap().trackers.len() * PAGE_SIZE;
        self.task.pcb.lock().shms.push(MapedSharedMemory {
            key: shmid,
            mem: trackers.unwrap(),
            start: vaddr.raw(),
            size,
        });
        Ok(vaddr.raw())
    }

    pub fn sys_shmctl(&self, shmid: usize, cmd: usize, arg: usize) -> SysResult {
        debug!("sys_shmctl @ shmid: {}, cmd: {}, arg: {}", shmid, cmd, arg);

        if cmd == 0 {
            // SHARED_MEMORY.lock().remove(&shmid);
            if let Some(map) = SHARED_MEMORY.lock().get_mut(&shmid) {
                *map.deleted.lock() = true;
            }
            return Ok(0);
        }
        Err(Errno::EPERM)
    }
}

