    /// personality: 设置进程执行域
    pub fn sys_personality(&self, persona: usize) -> SysResult {
        use core::sync::atomic::{AtomicUsize, Ordering};
        static PERSONALITY: AtomicUsize = AtomicUsize::new(0);
        let old = PERSONALITY.swap(persona, Ordering::Relaxed);
        debug!("sys_personality @ old: {:#x}, new: {:#x}", old, persona);
        Ok(old)
    }

    /// set_robust_list: 存储 robust list 头指针
    pub fn sys_set_robust_list(&self, head: usize, len: usize) -> SysResult {
        debug!("sys_set_robust_list @ head: {:#x}, len: {}", head, len);
        Ok(0)
    }

    #[cfg(target_arch = "x86_64")]
    pub fn sys_arch_prctl(&self, code: usize, addr: usize) -> SysResult {
        use libc_types::others::ArchPrctlCmd;
        use polyhal_trap::trapframe::TrapFrameArgs;
        use syscalls::Errno;

        let arch_prctl_code = ArchPrctlCmd::try_from(code).map_err(|_| Errno::EINVAL)?;
        debug!(
            "sys_arch_prctl @ code: {:?}, addr: {:#x}",
            arch_prctl_code, addr
        );
        let cx_ref = self.task.force_cx_ref();
        match arch_prctl_code {
            ArchPrctlCmd::SetFS => cx_ref[TrapFrameArgs::TLS] = addr,
            _ => {
                error!("arch prctl: {:#x?}", arch_prctl_code);
                return Err(Errno::EPERM);
            }
        }
        Ok(0)
    }
}

use core::cmp;

use alloc::{collections::VecDeque, sync::Arc};
use libc_types::poll::PollEvent;
use sync::Mutex;
use syscalls::Errno;
use vfscore::{INodeInterface, VfsResult};

pub struct SocketPair {
    inner: Arc<Mutex<VecDeque<u8>>>,
}

impl INodeInterface for SocketPair {
    fn writeat(&self, _offset: usize, buffer: &[u8]) -> VfsResult<usize> {
        let mut queue = self.inner.lock();
        if queue.len() > 0x50000 {
            Err(Errno::EWOULDBLOCK)
        } else {
            let wlen = buffer.len();
            queue.extend(buffer.iter());
            Ok(wlen)
        }
    }

    fn readat(&self, _offset: usize, buffer: &mut [u8]) -> VfsResult<usize> {
        let mut queue = self.inner.lock();
        let rlen = cmp::min(queue.len(), buffer.len());
        queue
            .drain(..rlen)
            .enumerate()
            .into_iter()
            .for_each(|(i, x)| {
                buffer[i] = x;
            });
        if rlen == 0 {
            Err(Errno::EWOULDBLOCK)
        } else {
            Ok(rlen)
        }
    }

    fn poll(&self, events: PollEvent) -> VfsResult<PollEvent> {
        let mut res = PollEvent::NONE;
        if events.contains(PollEvent::OUT) {
            if self.inner.lock().len() <= 0x50000 {
                res |= PollEvent::OUT;
            }
        }
        if events.contains(PollEvent::IN) {
            if self.inner.lock().len() > 0 {
                res |= PollEvent::IN;
            }
        }
        Ok(res)
    }
}

pub fn create_socket_pair() -> Arc<SocketPair> {
    Arc::new(SocketPair {
        inner: Arc::new(Mutex::new(VecDeque::new())),
    })
}

