use std::{env, fs, path::PathBuf};

#[allow(unused_macros)]
macro_rules! display {
    ($fmt:expr) => (println!("cargo:warning={}", format!($fmt)));
    ($fmt:expr, $($arg:tt)*) => (println!(concat!("cargo:warning=", $fmt), $($arg)*));
}

fn main() {
    let out_dir = PathBuf::from(env::var("OUT_DIR").expect("can't find manifest dir"));
    let img_relative_path = env::var("MOUNT_IMG_PATH").unwrap_or("mount.img".into());
    let project_dir =
        PathBuf::from(env::var("ROOT_MANIFEST_DIR").expect("can't find manifest directory"));

    let img_path = project_dir.join(img_relative_path);
    let img_path = img_path.to_str().expect("can't build a valid img path");
    fs::write(
        out_dir.join("inc.S"),
        format!(
            ".section .data
    .global ramdisk_start
    .global ramdisk_end
    .p2align 12
    ramdisk_start:
    .incbin \"{img_path}\"
    ramdisk_end:"
        ),
    )
    .expect("can't write ram file to out_dir");

    // fs::write(path, contents)

    // write module configuration to OUT_PATH, then it will be included in the main.rs
    println!("cargo:rerun-if-env-changed=MOUNT_IMG_PATH");
    println!("cargo:rerun-if-changed=mount.img");
    println!("cargo:rerun-if-changed=build.rs");
}

[package]
name = "fs"
version = "0.1.0"
edition = "2021"

# See more keys and their definitions at https://doc.rust-lang.org/cargo/reference/manifest.html

[dependencies]
log = "0.4"
bitflags = "2.0.2"
devfs = { workspace = true }
procfs = { workspace = true }
ramfs = { workspace = true }
vfscore = { workspace = true }
syscalls = { workspace = true }
sync = { workspace = true }
devices = { workspace = true }
libc-types = { workspace = true }

[target.'cfg(root_fs = "ext4_rs")'.dependencies]
ext4rsfs = { path = "../ext4rsfs" }

[target.'cfg(root_fs = "ext4")'.dependencies]
ext4fs = { path = "../ext4fs" }

[target.'cfg(root_fs = "fat32")'.dependencies.fatfs]
git = "https://github.com/byte-os/rust-fatfs.git"
# rev = "a3a834e"
default-features = false
features = ["alloc", "lfn", "unicode"]

fn main() {
    println!(r#"cargo::rustc-check-cfg=cfg(root_fs, values("fat32", "ext4", "ext4_rs"))"#);
    println!("cargo:rerun-if-env-changed=CARGO_CFG_ROOT_FS");
}

./filesystem/ext4fs/Cargo.toml:name = "ext4fs"
./filesystem/fs/Cargo.toml:ext4fs = { path = "../ext4fs" }
./filesystem/ext4fs/Cargo.toml:lwext4_rust = { git = "https://github.com/Azure-stars/lwext4_rust.git", default-features = false, rev = "ee5131c" }
